INSERT INTO smestuvanja (id, naslov, lokacija, cena_od_den, status, opis, link, slika) VALUES
                                                                                           (1, 'Вила Иван, Берово: Вила со базен и сауна и џакузи', 'Берово', 2000.0, 'СУПЕР БРЗ ДОМАЌИН', 'Луксузна вила крај Беровско Езеро со приватен базен, сауна и џакузи, идеална за романтичен одмор или релаксација. Опкружена со природа и тишина, нуди комплетна приватност и удобност.', 'https://kajak.mk/smestuvanje/44beb0cb-vila-ivan-berovsko-ezero', 'https://cdn.kajak.mk/static/85fc01bb-da34-dca4-c1e0-09a445b42df3.jpg'),
                                                                                           (2, 'Планинска викендица во Ѕвегор на 900мнв', 'Делчево', 3000.0, 'СУПЕР ДОМАЌИН', 'Планинска викендица на 900 метри надморска височина во село Ѕвегор, идеална за бегство во природа. Нуди мир, чист воздух и прекрасни планински пејзажи.', 'https://kajak.mk/smestuvanje/planinska-vikendica-vo-dzvegor-na-900mnv', 'https://cdn.kajak.mk/static/374c5e95-7979-6adf-7c26-99886169e935.jpg'),
                                                                                           (3, 'Студио во центарот на Охрид', 'Охрид', 2500.0, 'СУПЕР ДОМАЌИН', 'Уредно студио сместено во самото срце на Охрид, на пешачка оддалеченост од сите знаменитости и ресторани. Совршено за краток градски одмор или романтичен викенд.', 'https://kajak.mk/smestuvanje/studio-vo-kukja--ohrid-kajak', 'https://cdn.kajak.mk/static/c4205106-ed1a-eedf-376c-8e0e26f37fda.jpg'),
                                                                                           (4, 'Апартман во Аеродром, Скопје', 'Скопје', 2000.0, 'СУПЕР ДОМАЌИН', 'Современ апартман во населбата Аеродром, Скопје, со добра поврзаност со целиот град. Практичен избор за деловни патувања или краток престој во главниот град.', 'https://kajak.mk/smestuvanje/apartman-vo-aerodrom-skopje-kajak', 'https://cdn.kajak.mk/static/af4af600-0fdb-40bc-16db-f3c584e14d78.jpg'),
                                                                                           (5, 'Апартмани во Струга, Македонија', 'Струга', 2000.0, 'СУПЕР ДОМАЌИН', 'Пространи апартмани во Струга, на кратко растојание од Охридското Езеро и центарот на градот. Одличен избор за семејства или групи кои сакаат да го истражат Охридскиот регион.', 'https://kajak.mk/smestuvanje/3c8ebebd-apartmani-vo-struga-apartmani-gago', 'https://cdn.kajak.mk/static/a194a419-b6fe-10b2-e3dd-2c7ec60d0152.jpg'),
                                                                                           (6, 'Престојувајте во македонска куќа во с. Дихово', 'Битола', 3690.0, 'СУПЕР ДОМАЌИН', 'Автентична македонска куќа во мирното село Дихово, под падините на Пелистер. Нуди традиционален амбиент, домашна атмосфера и блискост до природните убавини на регионот.', 'https://kajak.mk/smestuvanje/prestojuvajte-vo-makedonska-kukja-vo-s-dihovo', 'https://cdn.kajak.mk/static/3d611b29-e5aa-5cde-b0c3-58a960149828.jpg'),
                                                                                           (7, 'Планинска вила во густата пехчевска шума близу водопадите', 'Пехчево', 4000.0, 'СУПЕР ДОМАЌИН', 'Планинска вила скриена во густата пехчевска шума, на чекор од убавите водопади на регионот. Совршена за љубители на природа и авантура кои бараат изолираност и мир.', 'https://kajak.mk/smestuvanje/chodosova-koliba-pehchevo', 'https://cdn.kajak.mk/static/d977182e-19a7-55b9-be18-eba27f551a87.jpg'),
                                                                                           (8, 'Нова вила во Радожда со прекрасен поглед', 'Струга', 3300.0, 'СУПЕР ДОМАЌИН', 'Нова вила во живописното село Радожда, на самиот брег на Охридското Езеро со прекрасен поглед. Романтична локација со задивувачки зајдисонци над езерото.', 'https://kajak.mk/smestuvanje/nova-vila-vo-radozhda-so-prekrasen-pogled', 'https://cdn.kajak.mk/static/28cee9f9-5999-1888-6ed7-03584b3e540c.jpg'),
                                                                                           (9, 'Апартман во Маврово за 5 лица', 'Маврово', 3200.0, 'СУПЕР ДОМАЌИН', 'Удобен апартман во Маврово за до 5 лица, во близина на ски-центарот и природниот парк. Идеален за планинарење лете и скијање зиме.', 'https://kajak.mk/smestuvanje/apartman-vo-mavrovo-za-5-lica-kajak', 'https://cdn.kajak.mk/static/80177c7f-d1db-bf17-8675-fca43181aae6.jpg'),
                                                                                           (10, 'Апартман во Маврово (туристичка населба)', 'Маврово', 4305.0, 'СУПЕР ДОМАЌИН', 'Апартман во туристичката населба на Маврово, опкружен со планини и нетакната природа. Совршен за активен одмор во секое годишно време.', 'https://kajak.mk/smestuvanje/apartman-vo-mavrovo-turistichka-naselba', 'https://cdn.kajak.mk/static/7be8ae6c-d212-39c1-94ff-deb95262c866.jpg'),
                                                                                           (11, 'Вила со базен во Радишани', 'Скопје', 17000.0, 'СУПЕР ДОМАЌИН', 'Ексклузивна вила со голем приватен базен во Радишани, Скопје. Луксузен простор за забави, групни собири или незаборавен викенд со пријатели.', 'https://kajak.mk/smestuvanje/vila-so-bazen-vo-radishanii', 'https://cdn.kajak.mk/static/449dc810-368a-d275-e9de-81e5e0b9a256.jpg'),
                                                                                           (12, 'Pet friendly апартмани во Трпејца', 'Охрид', 3200.0, 'СУПЕР ДОМАЌИН', 'Pet friendly апартмани во идиличното рибарско село Трпејца на Охридското Езеро. Одлична опција за љубители на животни кои сакаат да ги доживеат убавините на Охридскиот регион.', 'https://kajak.mk/smestuvanje/pet-friendly-apartmani-vo-trpejca', 'https://cdn.kajak.mk/static/ba64ec18-66c6-dfbc-45af-97fb451899d0.jpg'),
                                                                                           (13, 'Вила во Серменин на Кожуф планина', 'Гевгелија', 2000.0, 'СУПЕР ДОМАЌИН', 'Вила сместена во селото Серменин на подножјето на Кожуф Планина, со поглед на природните убавини на Гевгелискиот регион. Мирно место за одмор далеку од градската врева.', 'https://kajak.mk/smestuvanje/d030f077-vila-semeninski-chardak', 'https://cdn.kajak.mk/static/04bd4587-cdbd-3a94-dd04-8a4e5da311c6.jpg'),
                                                                                           (14, 'Сместување во стариот дел на градот: Кратово', 'Кратово', 6000.0, 'СУПЕР ДОМАЌИН', 'Историска куќа во стариот дел на Кратово, градот познат по своите средновековни кули и мостови. Уникатно искуство на живеење во жива историја.', 'https://kajak.mk/smestuvanje/house-of-sokolovi-kratovo', 'https://cdn.kajak.mk/static/9abcba01-be06-972c-92ea-b428a673a26f.jpg'),
                                                                                           (15, 'Модерни апартмани во Битола', 'Битола', 2000.0, 'СУПЕР ДОМАЌИН', 'Модерно опремени апартмани во центарот на Битола, на чекор од познатата Широка Скала. Одличен избор за истражување на историскиот град по достапна цена.', 'https://kajak.mk/smestuvanje/moderni-apartmani-vo-bitola', 'https://cdn.kajak.mk/static/06e4f507-0eda-5304-4189-c60ea0e83c74.JPG'),
                                                                                           (16, 'Апартмани во Елшани, Охрид со капацитет за цело друштво', 'Охрид', 3000.0, 'СУПЕР ДОМАЌИН', 'Апартмани во Елшани, мирно село на брегот на Охридското Езеро, со капацитет за поголема група. Идеално за семејни собири или пријателски викенди крај езерото.', 'https://kajak.mk/smestuvanje/b3d712bd-apartmani-vo-elshani-ohrid-so-kapacitet-za-celo-drushtvo', 'https://cdn.kajak.mk/static/c8a8f62a-566e-aa6c-d850-f32d76e2db34.jpg'),
                                                                                           (17, 'Dishli Hotel & Spa', 'Струга', 2199.0, 'СУПЕР ДОМАЌИН', 'Бутик хотел со СПА во Струга, нуди комбинација на удобност, третмани и релаксација. Совршен за пар кој бара луксузен одмор со поглед на Охридското Езеро.', 'https://kajak.mk/smestuvanje/dishli-hotel--spa', 'https://cdn.kajak.mk/static/8ab126d0-792d-d5ac-bf64-4bcd08413dfb.jpg'),
                                                                                           (18, 'Викендица во Вевчани', 'Вевчани', 6150.0, 'СУПЕР ДОМАЌИН', 'Викендица во прекрасното село Вевчани, познато по своите извори и уникатниот карневал. Аутентично македонско искуство во живописна природна средина.', 'https://kajak.mk/smestuvanje/7579e1b3-vikendica-vo-vevchani', 'https://cdn.kajak.mk/static/2a738bf1-9f15-687d-bf15-67be07665f89.jpg'),
                                                                                           (19, 'Камена планинска вила во Суви Лаки', 'Берово', 4000.0, 'МОМЕНТАЛНО НЕ РАБОТАТ', 'Камена планинска вила во Суви Лаки, Берово, опкружена со шума и природа. Забелешка: моментално не работат.', 'https://kajak.mk/smestuvanje/kamena-planinska-vila-vo-suvi-laki', 'https://cdn.kajak.mk/static/4457956e-d82d-91b1-e9a7-aa4de941f889.jpg'),
                                                                                           (20, 'Етно бунгалови во Старо Нагоричане', 'Крива Паланка', 3000.0, 'НОВО', 'Етно бунгалови во Старо Нагоричане, ново сместување со традиционален карактер и природен амбиент. Идеално за откривање на Криворечкиот регион.', 'https://kajak.mk/smestuvanje/etno-bungalovi-vo-staro-nagorichane', 'https://cdn.kajak.mk/static/26d4e770-f345-49f3-0d92-8cf51b272887.jpg'),
                                                                                           (21, 'Планинска вила со базен и сауна', 'Делчево', 3300.0, 'СУПЕР ДОМАЌИН', 'Планинска вила со базен и сауна во Делчево, идеална за група пријатели или семејство кое сака луксузен планински одмор. Комбинација на природа и удобност.', 'https://kajak.mk/smestuvanje/c8fb77c9-vila-gora-delchevo', 'https://cdn.kajak.mk/static/5e5e2b4b-f183-a95e-b8b6-1ea8b4aa5c80.jpg'),
                                                                                           (22, 'Вила Тони во Дојран со базен со солена вода, џакузи и сауна', 'Дојран', NULL, 'СУПЕР БРЗ ДОМАЌИН', 'Луксузна вила во Дојран со базен со солена вода, џакузи и сауна, на кратко растојание од езерото. Совршена за романтичен одмор или СПА викенд.', 'https://kajak.mk/smestuvanje/vila-vo-dojran-so-bazen-so-solena-voda-gakuzi-i-sauna', 'https://cdn.kajak.mk/static/16786b37-cdc7-f7c3-c34f-333545a8c2d2.jpg'),
                                                                                           (23, 'Планински апартмани на Попова Шапка', 'Попова Шапка', 5535.0, 'СУПЕР ДОМАЌИН', 'Планински апартмани на популарната скијачка дестинација Попова Шапка. Одличен избор за зимски одмор и скијање, но и за летно планинарење.', 'https://kajak.mk/smestuvanje/planinski-apartmani-na-popova-shapka', 'https://cdn.kajak.mk/static/e31fd6eb-88fc-cc05-56f3-768ffefe84e1.jpg'),
                                                                                           (24, 'Вила на Попова Шапка достапна за цело друштво', 'Попова Шапка', 4000.0, 'СУПЕР ДОМАЌИН', 'Пространа вила на Попова Шапка достапна за целото друштво, идеална за групни одмори во планинска средина. Нуди пристап до ски-патеки и планинарски патеки.', 'https://kajak.mk/smestuvanje/55e397c3-vila-177-popova-shapka', 'https://cdn.kajak.mk/static/11550b9e-1840-7dd1-9fdc-3a03257131e0.jpg'),
                                                                                           (25, 'Селска викендица во Орланци достапна на Кајак.мк', 'Кичево', 2500.0, 'СУПЕР ДОМАЌИН', 'Автентична селска викендица во Орланци, Кичево, со традиционален македонски карактер. Одлична опција за семејства кои сакаат мирен одмор во рурална средина.', 'https://kajak.mk/smestuvanje/selska-vikendica-vo-orlanci-dostapna-na-kajakmk', 'https://cdn.kajak.mk/static/da827468-17fd-0934-16de-2f3ad6326611.jpg'),
                                                                                           (26, 'Викендица во близина на Велес', 'Велес', 2000.0, 'СУПЕР ДОМАЌИН', 'Пријатна викендица во близина на Велес, идеална за краток бег во природа. Достапна по поволна цена за мирен викенд подалеку од градот.', 'https://kajak.mk/smestuvanje/vikendica-vo-blizina-na-veles', 'https://cdn.kajak.mk/static/6e053e1b-7fbc-f41c-d2d6-756b68ec6f08.jpg'),
                                                                                           (27, 'Селска викендица со базен и целосна приватност', 'Куманово', 5600.0, 'СУПЕР ДОМАЌИН', 'Луксузна селска викендица со приватен базен и целосна приватност во Кумановскиот регион. Идеална за групи и семејства кои бараат изолиран одмор.', 'https://kajak.mk/smestuvanje/selska-vikendica-za-celosna-privatnost', 'https://cdn.kajak.mk/static/542d0934-2b8b-80b4-f2f8-ddadd3bd3589.jpg'),
                                                                                           (28, 'Вила со базен, џакузи и одличен поглед на Скопје', 'Скопје', 15000.0, 'СУПЕР ДОМАЌИН', 'Ексклузивна вила со базен, џакузи и панорамски поглед на Скопје. Луксузно сместување за незаборавен одмор со прекрасна гледка кон градот.', 'https://kajak.mk/smestuvanje/a4c1955b-vila-so-bazen-gakuzi-i-odlichen-pogled-na-skopje', 'https://cdn.kajak.mk/static/da48add9-eb0d-691c-94cb-61504e491b33.jpg'),
                                                                                           (29, 'Апартмани за изнајмување во Берово, за цело друштво', 'Берово', 1750.0, 'СУПЕР ДОМАЌИН', 'Апартмани во Берово за цело друштво, по исклучително достапна цена. Добра базна точка за истражување на Малешевијата и Беровското Езеро.', 'https://kajak.mk/smestuvanje/046440db-apartmani-maleshevska-kukja-berovo', 'https://cdn.kajak.mk/static/58fc27b8-564e-3be3-fee0-8ad94dc384fe.jpg'),
                                                                                           (30, 'Пастелен апартман со уникатен ентериер во Охрид', 'Охрид', 4200.0, 'СУПЕР ДОМАЌИН', 'Пастелен апартман со уникатен и внимателно осмислен ентериер во Охрид. Совршена романтична средина за пар кој сака стил и удобност.', 'https://kajak.mk/smestuvanje/pastelen-apartman-so-unikaten-enterier-vo-ohrid', 'https://cdn.kajak.mk/static/6f813d6b-c045-f32f-9eea-e4928c80a9b3.jpg'),
                                                                                           (31, 'Етно уникатна вила во село Белица, Кичево', 'Кичево', 5000.0, 'СУПЕР ДОМАЌИН', 'Етно вила во автентичното село Белица, Кичево, со традиционален македонски декор. Уникатно искуство на рурален живот во убава природна средина.', 'https://kajak.mk/smestuvanje/etno-unikatna-vila-vo-selo-belica-kichevo', 'https://cdn.kajak.mk/static/dbfd7952-e680-7071-9b38-e533b6856bca.jpg'),
                                                                                           (32, 'Нови уникатни куќарки кај Марков Манастир', 'Скопје', 4500.0, 'СУПЕР ДОМАЌИН', 'Уникатни куќарки (tiny houses) во близина на Марков Манастир, Скопје. Необично и романтично сместување со историска атмосфера.', 'https://kajak.mk/smestuvanje/novi-unikatni-kukjarki-kaj-markov-manastir', 'https://cdn.kajak.mk/static/924414f1-ffe9-0c0b-e70c-51c8d23a2c01.jpg'),
                                                                                           (33, 'Апартмани во Стар Дојран, блиску до урбанизирана плажа', 'Дојран', 2750.0, 'СУПЕР ДОМАЌИН', 'Апартмани во Стар Дојран, блиску до уредената плажа на Дојранското Езеро. Одличен избор за летен одмор крај езерото.', 'https://kajak.mk/smestuvanje/7a2aa55a-bb-lake-view-apartments-dojran', 'https://cdn.kajak.mk/static/3bbc7f96-686c-7a10-5d8e-dc8c2cbe2995.jpg'),
                                                                                           (34, 'Апартмани во Преспа: Планина, езеро и природа', 'Преспа', 1600.0, 'СУПЕР ДОМАЌИН', 'Апартмани во Преспа со поглед на планината и езерото, идеални за еко-туризам и природен одмор. Одличен избор за истражување на националниот парк Пелистер.', 'https://kajak.mk/smestuvanje/apartmani-vo-prespa-planina-ezero-i-priroda', 'https://cdn.kajak.mk/static/0516fbdd-18c3-41e4-7359-8c155277bb50.jpg'),
                                                                                           (35, 'Модерни апартмани во Златибор', 'Србија', 4305.0, 'СУПЕР ДОМАЌИН', 'Модерни апартмани на популарната српска планинска дестинација Златибор. Одличен избор за планинарење и уживање во природата.', 'https://kajak.mk/smestuvanje/moderni-apartmani-vo-zlatibor', 'https://cdn.kajak.mk/static/e79c53e9-e288-1ddf-b941-84aaeed3ebcc.jpg'),
                                                                                           (36, 'Апартман во Переа (Peraia), Грција', 'Грција', 4633.0, 'СУПЕР ДОМАЌИН', 'Апартман во Переа, Грција, на кратко растојание од Солун и морето. Одлично за летен одмор со пристап до плажи.', 'https://kajak.mk/smestuvanje/apartman-vo-perea-peraia-grcija', 'https://cdn.kajak.mk/static/bded0878-cb8f-f303-af89-0aa192749bfb.jpg'),
                                                                                           (37, 'Вила со базен во околината на Скопје: Приватност и уживање со друштво', 'Скопје', 10000.0, 'СУПЕР ДОМАЌИН', 'Ексклузивна вила со базен во околината на Скопје, нуди целосна приватност и луксузен одмор за поголемо друштво. Идеална за прослави и групни собири.', 'https://kajak.mk/smestuvanje/vila-so-bazen-vo-okolinata-na-skopje-privatnost-i-uzhivanje-so-drushtvo', 'https://cdn.kajak.mk/static/a157e0f1-94e7-2154-cdd1-bfc6ada56cc2.jpg'),
                                                                                           (38, 'Хотел на Пониква', 'Кочани/Пониква', 2200.0, 'СУПЕР ДОМАЌИН', 'Хотел во живописното планинско подрачје Пониква, идеален за планинарење и уживање во природата. Добар избор за семејства и авантуристи.', 'https://kajak.mk/smestuvanje/b87e202e-hotel-konak-ponikva', 'https://cdn.kajak.mk/static/feec6979-051f-4a4a-a166-92c1ee30a541.jpg'),
                                                                                           (39, 'Апартман во Охрид – Строг Центар', 'Охрид', 7000.0, 'СУПЕР ДОМАЌИН', 'Апартман во строгиот центар на Охрид, на чекор од Охридското Езеро и сите историски знаменитости. Луксузна локација за незаборавен престој.', 'https://kajak.mk/smestuvanje/apartman-vo-ohrid--strog-centar-kajak', 'https://cdn.kajak.mk/static/acd48643-0d80-924a-b065-307134155aa9.jpg'),
                                                                                           (40, 'Апартман во Охрид со една спална соба', 'Охрид', 3400.0, 'СУПЕР ДОМАЌИН', 'Уреден апартман во Охрид со една спална соба, идеален за пар или самец кој сака да го доживее шармот на Охрид. Пешачка оддалеченост до езерото.', 'https://kajak.mk/smestuvanje/f50c53ce-apartman-vo-ohrid-so-edna-spalna-soba', 'https://cdn.kajak.mk/static/c4bd1ff4-49c1-c028-1996-2ef6b4303654.jpg'),
                                                                                           (41, 'Дрвена вила со базен во борова шума во Стрезовце', 'Куманово', 10000.0, 'СУПЕР ДОМАЌИН', 'Дрвена вила со приватен базен сместена во борова шума во Стрезовце, Куманово. Уникатен луксузен одмор во природа, со целосна приватност.', 'https://kajak.mk/smestuvanje/drvena-vila-so-bazen-za-letna-sezona-vo-strezovce', 'https://cdn.kajak.mk/static/5f992457-54d1-48ca-7f59-d6af0becd2f2.jpg'),
                                                                                           (42, 'Ексклузивни апартмани: Струга', 'Струга', 2700.0, 'СУПЕР ДОМАЌИН', 'Ексклузивни апартмани во Струга со модерен дизајн, на кратко растојание до езерото. Одличен спој на удобност и пристапност до природата.', 'https://kajak.mk/smestuvanje/ekskluzivni-apartmani-struga', 'https://cdn.kajak.mk/static/fc799e7e-5e03-d420-7c71-9a132b88d0f3.jpg'),
                                                                                           (43, 'Вила Иван, Берово: Вила со базен и сауна и џакузи', 'Берово', 2000.0, 'СУПЕР БРЗ ДОМАЌИН', 'Луксузна вила крај Беровско Езеро со приватен базен, сауна и џакузи. Комплетна релаксација во природна средина со највисок степен на удобност.', 'https://kajak.mk/smestuvanje/44beb0cb-vila-ivan-berovsko-ezero', 'https://cdn.kajak.mk/static/85fc01bb-da34-dca4-c1e0-09a445b42df3.jpg'),
                                                                                           (44, 'Апартман во центарот на Охрид', 'Охрид', 3000.0, 'СУПЕР ДОМАЌИН', 'Апартман во центарот на Охрид, на пешачка оддалеченост до езерото и старото јадро на градот. Практичен и пријатен избор за истражување на Охрид.', 'https://kajak.mk/smestuvanje/apartman-vo-centarot-na-ohrid-booking', 'https://cdn.kajak.mk/static/fc033bf8-d8ce-6384-dbbc-3bf2e9d70ed6.JPG'),
                                                                                           (45, 'Апартмани во Вевчани достапни на Кајак.мк', 'Вевчани', 2460.0, 'СУПЕР ДОМАЌИН', 'Апартмани во Вевчани, селото познато по своите извори, природата и карневалот. Убава рурална средина со автентичен македонски дух.', 'https://kajak.mk/smestuvanje/apartmani-vo-vevchani-dostapni-na-kajakmk', 'https://cdn.kajak.mk/static/7b0708fb-03f3-c0e8-df24-48a731f50102.JPG'),
                                                                                           (46, 'Вилата во Папрадиште', 'Велес', 1000.0, 'СУПЕР ДОМАЌИН', 'Мирна вила во селото Папрадиште, Велес, по исклучително достапна цена. Совршена за оние кои бараат тивок одмор во природа без да трошат многу.', 'https://kajak.mk/smestuvanje/vilata-vo-papradishte', 'https://cdn.kajak.mk/static/e7fb45c0-777d-0595-e8b5-024def5477eb.jpg'),
                                                                                           (47, 'Вила со базен на Велешко Езеро 2', 'Велес', 2990.0, 'СУПЕР ДОМАЌИН', 'Вила со базен на брегот на Велешкото Езеро, идеална за летен одмор со семејство или пријатели. Убав поглед и пристап до вода.', 'https://kajak.mk/smestuvanje/vila-lucija-veleshko-ezero', 'https://cdn.kajak.mk/static/b1a68ea5-88ad-843e-5e3b-64d2806aa069.jpg'),
                                                                                           (48, 'Апартмани во Скопје', 'Скопје', 2500.0, 'СУПЕР ДОМАЌИН', 'Апартмани во Скопје, удобно и пристапно сместување во главниот град. Добра опција за деловни посети или разгледување на Скопје.', 'https://kajak.mk/smestuvanje/e2c40440-apartmani-vo-skopje', 'https://cdn.kajak.mk/static/03b5b923-a8a3-1f63-7ad9-e6983dcb496c.jpg'),
                                                                                           (49, 'Апартмани во Скопје, Тафталиџе', 'Скопје', 2000.0, 'СУПЕР ДОМАЌИН', 'Апартмани во населбата Тафталиџе, Скопје, во мирна зелена средина на работ на градот. Одличен спој на градска пристапност и спокојство.', 'https://kajak.mk/smestuvanje/apartmani-vo-skopje-taftalige', 'https://cdn.kajak.mk/static/323a4122-3712-080d-b4c8-2054b9ab5857.jpg'),
                                                                                           (50, 'Lux apartment Dolce Casa Skopje', 'Скопје', 2152.0, 'СУПЕР ДОМАЌИН', 'Луксузен апартман Dolce Casa во Скопје со префинет дизајн и висококвалитетна опрема. Совршен за пар или деловни патници кои бараат стил и удобност.', 'https://kajak.mk/smestuvanje/40e8f7d3-lux-apartment-dolce-casa-skopje', 'https://cdn.kajak.mk/static/2703e27b-c56a-0eeb-451f-d2baf00957bc.jpg'),
                                                                                           (51, 'Вила во Горна Белица', 'Струга', 2500.0, 'СУПЕР ДОМАЌИН', 'Вила во мирното село Горна Белица, Струга, опкружена со природа и виногради. Идеална за одмор во природа, блиску до Охридско Езеро.', 'https://kajak.mk/smestuvanje/791cd5eb-vila-vo-gorna-belica', 'https://cdn.kajak.mk/static/5ab168c3-1e06-551f-9c37-834bacb3ceab.jpeg'),
                                                                                           (52, 'Вила со базен и џакузи во Горно Соње', 'Скопје', 12300.0, 'СУПЕР ДОМАЌИН', 'Луксузна вила со голем базен и џакузи во Горно Соње, со панорамски поглед. Ексклузивно сместување за незаборавен одмор.', 'https://kajak.mk/smestuvanje/2e218ec5-vila-so-bazen-vo-gorno-sonje', 'https://cdn.kajak.mk/static/ad0370b1-a335-5f7a-bdd6-b264305696f7.jpg'),
                                                                                           (53, 'Викендица на Пелистер: Трново', 'Битола', 2500.0, 'СУПЕР ДОМАЌИН', 'Викендица на падините на Пелистер во селото Трново, со поглед на Битолското Поле. Одлична почетна точка за планинарење на Пелистер.', 'https://kajak.mk/smestuvanje/82704bce-vikendica-na-pelister-trnovo', 'https://cdn.kajak.mk/static/098eadde-41ae-fc93-35f0-02563145f221.jpeg'),
                                                                                           (54, 'Модерен апартман во Маврово за 6 гости', 'Маврово', 6000.0, 'СУПЕР ДОМАЌИН', 'Модерен апартман во Маврово за до 6 гости, идеален за поголемо друштво или семејство. Одлична локација за планинарење и ски.', 'https://kajak.mk/smestuvanje/moderen-apartman-vo-mavrovo-za-6-gosti', 'https://cdn.kajak.mk/static/0e6ff028-6aee-5a5f-59aa-c0e64f2d02fb.jpg'),
                                                                                           (55, 'Апартман во Скопје Ист Гејт Ливинг', 'Скопје', 2750.0, 'СУПЕР ДОМАЌИН', 'Апартман во модерниот комплекс Ист Гејт Ливинг, Скопје, со сите современи погодности. Практичен избор за деловни патувања или посети на главниот град.', 'https://kajak.mk/smestuvanje/apartman-vo-skopje-ist-gejt-living', 'https://cdn.kajak.mk/static/0bbaf891-1c2f-4629-17b6-bb6679c5073f.jpg'),
                                                                                           (56, 'Ловен дом Берово', 'Берово', 3500.0, 'СУПЕР ДОМАЌИН', 'Ловен дом во Берово, со автентичен карактер и близина до Беровското Езеро и шумите. Идеален за ловџии, планинари и љубители на природа.', 'https://kajak.mk/smestuvanje/loven-dom-berovo', 'https://cdn.kajak.mk/static/b3a45e24-db47-1133-db4a-b8c24bdfb943.jpg'),
                                                                                           (57, 'Апартман во Крушево', 'Крушево', 3000.0, 'СУПЕР ДОМАЌИН', 'Уреден апартман во Крушево, највисокиот град во Македонија со богата историја. Одличен за истражување на историјата и природните убавини на регионот.', 'https://kajak.mk/smestuvanje/f3564256-apartman-paik-krushevo', 'https://cdn.kajak.mk/static/395f2fd1-2450-e23c-9048-d0a966f2b44c.jpg'),
                                                                                           (58, 'Вила со студија во Крушево', 'Крушево', 1500.0, 'СУПЕР ДОМАЌИН', 'Вила со студија во Крушево по достапна цена, добра опција за семејства или групи. Уживање во планинскиот воздух на највисокиот македонски град.', 'https://kajak.mk/smestuvanje/vila-so-studija-vo-krushevo', 'https://cdn.kajak.mk/static/7b2547aa-0338-ab40-7637-1de2ce852706.jpg'),
                                                                                           (59, 'Вила во село Белица, Македонија', 'Македонски Брод', 1000.0, 'СУПЕР ДОМАЌИН', 'Вила во мирното село Белица, Македонски Брод, по исклучително ниска цена. Совршена за оние кои бараат целосно отстапување во рурална природа.', 'https://kajak.mk/smestuvanje/b2cafdf4-vila-belica', 'https://cdn.kajak.mk/static/8eb8a68e-55aa-1774-680b-ee1eb97bc5f3.jpg'),
                                                                                           (60, 'Апартман во Македонски Брод со поглед на планина', 'Македонски Брод', 3500.0, 'СУПЕР ДОМАЌИН', 'Апартман во Македонски Брод со прекрасен поглед на планината, идеален за авантуристи и љубители на природа. Добра точка за истражување на Јадовник и Стогово.', 'https://kajak.mk/smestuvanje/eb09b487-apartman-bragorski-makedonski-brod', 'https://cdn.kajak.mk/static/373bf7d1-6739-3f85-d52d-a6301e76dbf3.jpg'),
                                                                                           (61, 'Прекрасни бунгалови опколени со многу зеленило на Охридско езеро', 'Охрид', 4000.0, 'СУПЕР ДОМАЌИН', 'Прекрасни бунгалови опколени со зеленило, директно на брегот на Охридското Езеро. Романтична и уникатна средина за незаборавен летен одмор.', 'https://kajak.mk/smestuvanje/33fe2108-prekrasni-bungalovi-opkoleni-so-mnogu-zelenilo-na-ohridsko-ezero', 'https://cdn.kajak.mk/static/27f8a4e9-afe5-ef1f-e0fd-1e2ea843edc0.jpg'),
                                                                                           (62, 'Уникатно рурално сместување – село Модрич', 'Струга', 3000.0, 'СУПЕР ДОМАЌИН', 'Уникатно рурално сместување во селото Модрич, Струга, со традиционален македонски карактер. Автентично искуство далеку од масовниот туризам.', 'https://kajak.mk/smestuvanje/unikatno-ruralno-smestuvanje--selo-modrich', 'https://cdn.kajak.mk/static/080eead9-3a0f-a2ee-1a51-087335db6c90.jpg'),
                                                                                           (63, 'Апартмани во Ханиоти, Грција', 'Грција', 11500.0, 'СУПЕР ДОМАЌИН', 'Апартмани во Ханиоти, Халкидики, Грција — популарна туристичка дестинација на Медитеранот. Летен одмор со море, плажи и грчка гастрономија.', 'https://kajak.mk/smestuvanje/apartmani-vo-hanioti-grcija', 'https://cdn.kajak.mk/static/357aede0-0336-f870-54c4-3bc185d345d5.jpg');
